const body = $input.first().json.body || $input.first().json;
const id = body.id;
if (!id) return [{ json: { success: false, error: 'id requis' } }];

const sets = [];
const b = body;
if (b.nom !== undefined) sets.push(`nom = '${b.nom}'`);
if (b.description !== undefined) sets.push(`description = '${b.description}'`);
if (b.categorie !== undefined) sets.push(`categorie = '${b.categorie}'`);
if (b.icon !== undefined) sets.push(`icon = '${b.icon}'`);
if (b.setupPrice !== undefined) sets.push(`setup_price = ${b.setupPrice}`);
if (b.monthlyPrice !== undefined) sets.push(`monthly_price = ${b.monthlyPrice}`);
if (b.complexity !== undefined) sets.push(`complexity = '${b.complexity}'::"AutomationComplexity"`);
if (b.workflowCount !== undefined) sets.push(`workflow_count = ${b.workflowCount}`);
if (b.isActive !== undefined) sets.push(`is_active = ${b.isActive}`);
if (b.ordre !== undefined) sets.push(`ordre = ${b.ordre}`);
if (b.features !== undefined) sets.push(`features = '${JSON.stringify(b.features)}'::jsonb`);
if (b.workflowTemplates !== undefined) sets.push(`workflow_templates = '${JSON.stringify(b.workflowTemplates)}'::jsonb`);

if (sets.length === 0) return [{ json: { success: false, error: 'Aucun champ a modifier' } }];

const query = `UPDATE automation_catalog SET ${sets.join(', ')}, updated_at = NOW() WHERE id = '${id}'::uuid RETURNING id, code, nom`;

return [{ json: { query, id, valid: true } }];
